from sentence_transformers import CrossEncoder
from tabulate import tabulate

MODELS = [
    "cross-encoder/ms-marco-MiniLM-L-6-v2",  # https://sbert.net/docs/cross_encoder/pretrained_models.html
    "cross-encoder/ms-marco-MiniLM-L-12-v2",
    "cross-encoder/stsb-roberta-base",
    "BAAI/bge-reranker-base",
    "BAAI/bge-reranker-large",
]
SENTENCE_PAIRS = [
    ("This is the same sentence!", "This is the same sentence!"),
    ("This is the same sentence!", "This is the same sentence?"),
    ("This is the same sentence!", "This is NOT the same sentence!"),
    ("This is the same sentence!", "NONONON!! This is not correct"),
    ("This is the same sentence!", "927593285++aa_"),
    ("a", "a"),
    ("1", "1"),
    ("1", "Today is a wonderful day. Habe ich Recht?\nÜÜÜÜ"),
]
# Preload all models
model_instances = {name: CrossEncoder(name) for name in MODELS}
# Prepare table rows
table = []
for query, response in SENTENCE_PAIRS:
    row = [f"Q: {query}\nA: {response}"]
    for model_name in MODELS:
        model = model_instances[model_name]
        score = model.predict([(query, response)])[0]
        row.append(f"{score:.4f}")
    table.append(row)
# Header row
headers = ["Query–Response"] + MODELS
# Print the table
print(tabulate(table, headers=headers, tablefmt="grid"))

